# acme_llm_client/client.py
# pip install anthropic openai opentelemetry-sdk

from __future__ import annotations
import time, random
from dataclasses import dataclass
from typing import Protocol, Any
from opentelemetry import trace

# --- shared data model ---

@dataclass
class LLMRequest:
    messages: list[dict[str, Any]]
    max_tokens: int = 1024
    system: str | None = None
    temperature: float = 1.0
    task_type: str = "default"  # used by ModelRouter

@dataclass
class LLMResponse:
    text: str
    input_tokens: int
    output_tokens: int
    model: str
    provider: str
    cost_usd: float

# --- pricing table (USD per million tokens, as of 2025) ---

PRICING: dict[str, dict[str, float]] = {
    "claude-haiku-3": {"input": 0.25, "output": 1.25},
    "claude-sonnet-4-5": {"input": 3.00, "output": 15.00},
    "gpt-4o-mini":   {"input": 0.15, "output": 0.60},
    "gpt-4o":        {"input": 2.50, "output": 10.00},
}

def _calc_cost(model: str, input_tokens: int, output_tokens: int) -> float:
    prices = PRICING.get(model, {"input": 0.0, "output": 0.0})
    return (input_tokens * prices["input"] + output_tokens * prices["output"]) / 1_000_000

# --- provider protocol ---

class LLMProvider(Protocol):
    def complete(self, request: LLMRequest) -> LLMResponse: ...

# --- retry wrapper ---

class _RateLimitError(Exception):
    """Unified rate-limit exception — adapters raise this."""
    def __init__(self, retry_after: float = 0.0):
        self.retry_after = retry_after

def with_retry(provider: LLMProvider, max_retries: int = 4) -> LLMProvider:
    """Wraps a provider to retry on rate limits with exponential backoff + jitter."""
    class RetryingProvider:
        def complete(self, request: LLMRequest) -> LLMResponse:
            for attempt in range(max_retries + 1):
                try:
                    return provider.complete(request)
                except _RateLimitError as exc:
                    if attempt == max_retries:
                        raise
                    wait = exc.retry_after or (2 ** attempt + random.uniform(0, 1))
                    time.sleep(wait)
    return RetryingProvider()  # type: ignore[return-value]

# --- OTel-instrumented facade ---

tracer = trace.get_tracer("acme_llm_client")

class LLMClient:
    """Top-level client: route → budget check → call → cost track → span."""

    def __init__(self, provider: LLMProvider):
        self._provider = with_retry(provider)

    def complete(self, request: LLMRequest) -> LLMResponse:
        with tracer.start_as_current_span("llm.complete") as span:
            span.set_attribute("llm.task_type", request.task_type)
            resp = self._provider.complete(request)
            span.set_attribute("llm.model", resp.model)
            span.set_attribute("llm.input_tokens", resp.input_tokens)
            span.set_attribute("llm.output_tokens", resp.output_tokens)
            span.set_attribute("llm.cost_usd", resp.cost_usd)
            return resp

# acme_llm_client/adapters.py

import anthropic
import openai
from .client import LLMRequest, LLMResponse, _RateLimitError, _calc_cost

class AnthropicAdapter:
    """Thin adapter over the Anthropic Python SDK."""

    DEFAULT_MODEL = "claude-haiku-3"

    def __init__(self, model: str = DEFAULT_MODEL):
        self._model = model
        self._client = anthropic.Anthropic()  # reads ANTHROPIC_API_KEY from env

    def complete(self, request: LLMRequest) -> LLMResponse:
        kwargs: dict = dict(
            model=self._model,
            max_tokens=request.max_tokens,
            messages=request.messages,
        )
        if request.system:
            kwargs["system"] = request.system
        try:
            msg = self._client.messages.create(**kwargs)
        except anthropic.RateLimitError as exc:
            # Read retry-after from headers if available
            retry_after = float(exc.response.headers.get("retry-after", 0))
            raise _RateLimitError(retry_after=retry_after) from exc
        cost = _calc_cost(self._model, msg.usage.input_tokens, msg.usage.output_tokens)
        return LLMResponse(
            text=msg.content[0].text,
            input_tokens=msg.usage.input_tokens,
            output_tokens=msg.usage.output_tokens,
            model=self._model,
            provider="anthropic",
            cost_usd=cost,
        )


class OpenAIAdapter:
    """Thin adapter over the OpenAI Python SDK."""

    DEFAULT_MODEL = "gpt-4o-mini"

    def __init__(self, model: str = DEFAULT_MODEL):
        self._model = model
        self._client = openai.OpenAI()  # reads OPENAI_API_KEY from env

    def complete(self, request: LLMRequest) -> LLMResponse:
        messages = request.messages[:]
        if request.system:
            messages = [{"role": "system", "content": request.system}] + messages
        try:
            resp = self._client.chat.completions.create(
                model=self._model,
                max_tokens=request.max_tokens,
                messages=messages,
            )
        except openai.RateLimitError as exc:
            raise _RateLimitError() from exc
        usage = resp.usage
        cost = _calc_cost(self._model, usage.prompt_tokens, usage.completion_tokens)
        return LLMResponse(
            text=resp.choices[0].message.content or "",
            input_tokens=usage.prompt_tokens,
            output_tokens=usage.completion_tokens,
            model=self._model,
            provider="openai",
            cost_usd=cost,
        )


# --- factory ---

def create_client(provider: str = "anthropic", model: str | None = None) -> "LLMClient":
    """Instantiate the correct adapter and wrap it in LLMClient."""
    from .client import LLMClient
    if provider == "anthropic":
        return LLMClient(AnthropicAdapter(model or AnthropicAdapter.DEFAULT_MODEL))
    elif provider == "openai":
        return LLMClient(OpenAIAdapter(model or OpenAIAdapter.DEFAULT_MODEL))
    raise ValueError(f"Unknown provider: {provider!r}")
